package main

import (
	"gno.land/r/gov/dao"
	valv3 "gno.land/r/sys/validators/v3"
)

func main(cur realm) {
	r := valv3.NewValidatorProposalRequest(
		cross(cur),
		[]valv3.ValoperChange{
			valv3.NewValoperChange(address("g1thrjnx75dgc95qed7x9edd0rvvpj5d5vevj50h"), 1),
		},
		"Add 1 validator(s) to the valset",
		"Batch-add 1 operator(s) to the active valset with voting power 1.",
	)
	pid := dao.MustCreateProposal(cross(cur), r)
	dao.MustVoteOnProposalSimple(cross(cur), int64(pid), "YES")
	dao.ExecuteProposal(cross(cur), pid)
}

